from dataclasses import dataclass


@dataclass
class ReactiveAgent:
    """
    Simplest reasoning strategy: map percept directly to action via rules.
    No intermediate reasoning steps; no memory.
    """

    def act(self, percept: dict) -> str:
        temp = percept.get("temperature_c")
        if temp is None:
            return "idle"
        if temp < 18:
            return "heat_on"
        if temp > 24:
            return "cool_on"
        return "idle"


agent = ReactiveAgent()
print(agent.act({"temperature_c": 16}))  # "heat_on"
print(agent.act({"temperature_c": 22}))  # "idle"
