import anthropic
import json


def react_loop(
    goal: str,
    tools: list[dict],
    tool_dispatch: dict,
    max_turns: int = 10,
) -> str:
    """
    ReAct pattern: interleave thinking (model text) with acting (tool calls)
    and observing (tool results) until the model returns a final answer.
    """
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": goal}]

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )

        # Append the model's response
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model decided it has the answer
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        # Process tool calls (the "Act" step) and collect observations
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                fn = tool_dispatch.get(block.name)
                result = fn(**block.input) if fn else {"error": "unknown tool"}
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })

        if tool_results:
            messages.append({"role": "user", "content": tool_results})

    return "max_turns reached without final answer"

from dataclasses import dataclass, field


@dataclass
class Task:
    id: str
    description: str
    depends_on: list[str] = field(default_factory=list)
    done: bool = False


@dataclass
class TaskPlan:
    """An explicit ordered task graph generated by the reasoning step."""

    tasks: list[Task]

    def next_ready(self) -> Task | None:
        """Return the next undone task whose dependencies are all satisfied."""
        done_ids = {t.id for t in self.tasks if t.done}
        for task in self.tasks:
            if not task.done and all(dep in done_ids for dep in task.depends_on):
                return task
        return None

    def mark_done(self, task_id: str) -> None:
        for t in self.tasks:
            if t.id == task_id:
                t.done = True

    def is_complete(self) -> bool:
        return all(t.done for t in self.tasks)


# Example: plan to research and write a report
plan = TaskPlan(tasks=[
    Task("search",  "Search for relevant sources"),
    Task("read",    "Read and summarise each source",     depends_on=["search"]),
    Task("outline", "Create report outline",              depends_on=["read"]),
    Task("write",   "Write the full report",              depends_on=["outline"]),
    Task("review",  "Review and polish the draft",        depends_on=["write"]),
])

while not plan.is_complete():
    task = plan.next_ready()
    print(f"Executing: {task.description}")
    # ... execute the task ...
    plan.mark_done(task.id)

import pytest
from unittest.mock import patch, MagicMock


class TestReactiveAgent:
    def test_low_temperature_heats(self):
        agent = ReactiveAgent()
        assert agent.act({"temperature_c": 15}) == "heat_on"

    def test_high_temperature_cools(self):
        agent = ReactiveAgent()
        assert agent.act({"temperature_c": 26}) == "cool_on"

    def test_in_range_idles(self):
        agent = ReactiveAgent()
        assert agent.act({"temperature_c": 21}) == "idle"

    def test_missing_sensor_idles(self):
        agent = ReactiveAgent()
        assert agent.act({}) == "idle"     # no temperature key — safe default


class TestTaskPlan:
    def test_first_ready_task_has_no_deps(self):
        plan = TaskPlan(tasks=[
            Task("a", "step A"),
            Task("b", "step B", depends_on=["a"]),
        ])
        assert plan.next_ready().id == "a"

    def test_dependency_blocks_task(self):
        plan = TaskPlan(tasks=[
            Task("a", "step A"),
            Task("b", "step B", depends_on=["a"]),
        ])
        # "b" is not ready until "a" is done
        ready = {t.id for t in plan.tasks if plan.next_ready().id == t.id}
        assert "b" not in ready

    def test_complete_after_all_done(self):
        plan = TaskPlan(tasks=[Task("a", "step A")])
        assert not plan.is_complete()
        plan.mark_done("a")
        assert plan.is_complete()
